#include <stdio.h>
#include <stdlib.h>
#define MAX 10000

// Define the structure for a tree node
typedef struct Node {
    int val;
    struct Node* left;
    struct Node* right;
} Node;

// Function to create a new tree node
Node* createNode(int val) {
    Node* newNode = (Node*) malloc(sizeof(Node));
    if (!newNode) {
        printf("Memory error
");
        return NULL;
    }
    newNode->val = val;
    newNode->left = newNode->right = NULL;
    return newNode;
}

// Function to traverse the tree and find paths with given sum
void traverse(Node* root, int target, int* path, int* pathLen, int** paths, int* numPaths) {
    if (root == NULL) return;
    path[*pathLen] = root->val;
    (*pathLen)++;
    if (root->left == NULL && root->right == NULL) {
        int sum = 0;
        for (int i = 0; i < *pathLen; i++) {
            sum += path[i];
        }
        if (sum == target) {
            // Add the path to the result list
            (*numPaths)++;
            for (int i = 0; i < *pathLen; i++) {
                paths[*numPaths - 1][i] = path[i];
            }
        }
    } else {
        traverse(root->left, target, path, pathLen, paths, numPaths);
        traverse(root->right, target, path, pathLen, paths, numPaths);
    }
    (*pathLen)--;
}

int main() {
    int N, target;
    scanf("%d %d", &N, &target);
    Node* root = NULL;
    int** paths = (int**) malloc(N * sizeof(int*));
    for (int i = 0; i < N; i++) {
        paths[i] = (int*) malloc(N * sizeof(int));
    }
    int* path = (int*) malloc(N * sizeof(int));
    int pathLen = 0;
    int numPaths = 0;
    // Read the tree edges and construct the tree
    Node* nodes[N];
    for (int i = 0; i < N; i++) {
        nodes[i] = createNode(i + 1);
    }
    for (int i = 0; i < N - 1; i++) {
        int pi, ci;
        char Ri;
        scanf("%d %d %c", &pi, &ci, &Ri);
        if (Ri == 'L') {
            nodes[pi - 1]->left = nodes[ci - 1];
        } else {
            nodes[pi - 1]->right = nodes[ci - 1];
        }
    }
    root = nodes[0];
    // Call the traverse function
    traverse(root, target, path, &pathLen, paths, &numPaths);
    // Print the paths
    for (int i = 0; i < numPaths; i++) {
        for (int j = 0; j < N; j++) {
            if (paths[i][j] != 0) {
                printf("%d ", paths[i][j]);
            }
        }
        printf("\n");
    }
    return 0;
}

