#include <iostream>
#include <vector>
using namespace std;

// Define the structure for a tree node
struct Node {
    int val;
    Node* left;
    Node* right;
    Node(int node_value) {
        val = node_value;
        left = right = NULL;
    }
};

// Function to traverse the tree and find paths with given sum
void traverse(Node* root, vector<vector<int>>& paths, vector<int> path, int target, int currentSum) {
    if (root == NULL) return;
    path.push_back(root->val);
    currentSum += root->val;
    if (root->left == NULL && root->right == NULL) {
        if (currentSum == target) {
            paths.push_back(path);
        }
    } else {
        traverse(root->left, paths, path, target, currentSum);
        traverse(root->right, paths, path, target, currentSum);
    }
    path.pop_back();
}

int main() {
    int N, target;
    cin >> N >> target;
    Node* root = NULL;
    vector<vector<int>> paths;
    vector<int> path;
    Node* nodes[N];
    for (int i = 0; i < N; i++) {
        nodes[i] = new Node(i + 1);
    }
    for (int i = 0; i < N - 1; i++) {
        int pi, ci;
        char Ri;
        cin >> pi >> ci >> Ri;
        if (Ri == 'L') {
            nodes[pi - 1]->left = nodes[ci - 1];
        } else {
            nodes[pi - 1]->right = nodes[ci - 1];
        }
    }
    root = nodes[0];
    // Call the traverse function
    traverse(root, paths, path, target, 0);
    // Print the paths
    for (auto& p : paths) {
        for (int node : p) {
            cout << node << " ";
        }
        cout << endl;
    }
    return 0;
}

