import java.util.ArrayList;
import java.util.List;
import java.util.Scanner;

// Define the structure for a tree node
class Node {
    int val;
    Node left;
    Node right;
    Node(int node_value) {
        val = node_value;
        left = right = null;
    }
}

public class Main {
    // Function to traverse the tree and find paths with given sum
    private void traverse(Node root, List<List<Integer>> paths, List<Integer> path, int target, int currentSum) {
        if (root == null) return;
        path.add(root.val);
        currentSum += root.val;
        if (root.left == null && root.right == null) {
            if (currentSum == target) {
                paths.add(new ArrayList<>(path));
            }
        } else {
            traverse(root.left, paths, path, target, currentSum);
            traverse(root.right, paths, path, target, currentSum);
        }
        path.remove(path.size() - 1);
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int N = sc.nextInt();
        int target = sc.nextInt();
        Node root = null;
        List<List<Integer>> paths = new ArrayList<>();
        List<Integer> path = new ArrayList<>();
        Node[] nodes = new Node[N];
        for (int i = 0; i < N; i++) {
            nodes[i] = new Node(i + 1);
        }
        for (int i = 0; i < N - 1; i++) {
            int pi = sc.nextInt();
            int ci = sc.nextInt();
            char Ri = sc.next().charAt(0);
            if (Ri == 'L') {
                nodes[pi - 1].left = nodes[ci - 1];
            } else {
                nodes[pi - 1].right = nodes[ci - 1];
            }
        }
        root = nodes[0];
        // Call the traverse function
        new Main().traverse(root, paths, path, target, 0);
        // Print the paths
        for (List<Integer> p : paths) {
            for (int node : p) {
                System.out.print(node + " ");
            }
            System.out.println();
        }
    }
}

