function traverse(root, paths, path, target, currentSum) {
    if (!root) return;
    path.push(root.val);
    currentSum += root.val;
    if (!root.left && !root.right) {
        if (currentSum === target) {
            paths.push([...path]);
        }
        path.pop();
        return;
    }
    traverse(root.left, paths, path, target, currentSum);
    traverse(root.right, paths, path, target, currentSum);
    path.pop();
}

